-- Seed data: inserts the two test question banks (modeler / leadership)
-- verbatim from content/modeler-test.json and content/leadership-test.json.
-- Safe to re-run: upserts on conflict.

insert into public.tests (id, title, duration_minutes, schema)
values (
  'modeler',
  'SCORE — Modeler / Senior Modeler Assessment',
  30,
  $modeler_schema${"testId":"modeler","program":"BIMstream SCORE","programFullName":"Situational Competency & Organizational Readiness Evaluation","title":"SCORE — Modeler / Senior Modeler Assessment","durationMinutes":30,"audience":"BIM Modelers and Senior Modelers","description":"Purely HR/behavioral instrument, 30 questions at ~60 seconds each. Technical/software skill is assessed separately (technical test + Personal Interview), so this test carries no technical items at all. Weighted for an individual-contributor role: Team Play, Communication, and Problem-Solving get the most questions; Leadership is present at a lighter weight to spot early potential; Dispute Resolution, Organizational Mindset, and Ethics carry small dedicated quotas but ethics-concern flags can surface on any question, not just the dedicated ones.","topicWeights":{"TP":7,"CM":6,"PS":6,"LD":4,"DR":3,"OM":2,"ET":2},"sections":[{"type":"situational_judgment","instructions":"Choose the option that best reflects how you would actually act. There is no single 'correct' answer — pick the one truest to your instinct.","questions":[{"id":"M-TP-01","topic":"TP","prompt":"A new teammate joins mid-project, unfamiliar with your studio's model standards, while you're on a tight deadline yourself. What do you do?","options":[{"text":"Point them to the standards doc and let them figure it out — you don't have time.","trait_deltas":{"TP":-2,"CM":-1}},{"text":"Take 15-20 minutes to walk them through the essentials now, then check in with them later.","trait_deltas":{"TP":2,"CM":1,"LD":1}},{"text":"Ask someone else on the team to onboard them instead.","trait_deltas":{"TP":-1}},{"text":"Ignore them until they ask you directly for help.","trait_deltas":{"TP":-2,"CM":-1}}]},{"id":"M-TP-02","topic":"TP","prompt":"A colleague on another discipline's team is overloaded and asks for informal help outside your assigned tasks. What do you do?","options":[{"text":"Decline — it's not your task list.","trait_deltas":{"TP":-1}},{"text":"Help without limit even if it seriously risks your own deadline, without telling anyone.","trait_deltas":{"TP":1,"PS":-1,"CM":-1}},{"text":"Offer specific, bounded help and let your own lead know about the trade-off.","trait_deltas":{"TP":2,"CM":2,"LD":1}},{"text":"Offer to help 'later' without committing to anything concrete.","trait_deltas":{"TP":-1,"CM":-1}}]},{"id":"M-TP-03","topic":"TP","prompt":"In a team meeting, credit for a successful clash-resolution effort gets attributed mostly to someone who did less of the actual work. What do you do?","options":[{"text":"Say nothing — it's not worth the awkwardness.","trait_deltas":{"TP":-1,"CM":-1}},{"text":"Correct the record on the spot, emphasizing your own contribution assertively.","trait_deltas":{"TP":-1,"CM":-1,"DR":-1}},{"text":"Mention the fuller picture calmly and factually, crediting everyone who contributed, including yourself.","trait_deltas":{"TP":2,"CM":2}},{"text":"Complain about it privately to other teammates afterward.","trait_deltas":{"TP":-2,"CM":-1}}]},{"id":"M-TP-04","topic":"TP","prompt":"You notice a teammate quietly struggling, and their slipping work is starting to threaten the team's shared deadline. What do you do?","options":[{"text":"Focus only on your own tasks — it's their responsibility.","trait_deltas":{"TP":-2,"LD":-1}},{"text":"Report their struggling to your manager immediately without talking to them first.","trait_deltas":{"TP":-1,"CM":-1}},{"text":"Check in with them directly and privately, understand what's going on, and offer specific support.","trait_deltas":{"TP":2,"CM":2,"LD":1}},{"text":"Quietly pick up their slack yourself without saying anything to them or anyone else.","trait_deltas":{"TP":0,"PS":-1,"CM":-1}}]},{"id":"M-TP-05","topic":"TP","prompt":"Your project wins client praise, but a teammate who contributed less publicly claims most of the credit in front of others. What's your reaction?","options":[{"text":"Publicly dispute their claim in the moment.","trait_deltas":{"TP":-1,"DR":-1,"CM":-1}},{"text":"Let it go completely and never mention it, even though it bothers you.","trait_deltas":{"TP":0,"CM":-1}},{"text":"Calmly and factually acknowledge the full team's contribution afterward, including your own, without making it confrontational.","trait_deltas":{"TP":2,"CM":2}},{"text":"Start doing the same thing yourself in future 'to even the score.'","trait_deltas":{"TP":-2,"ET":-1}}]},{"id":"M-TP-06","topic":"TP","prompt":"Helping another discipline hit their deadline would require you to slightly adjust your own schedule, at some real cost to you. What's your approach?","options":[{"text":"Refuse, since it's not your deadline to worry about.","trait_deltas":{"TP":-2}},{"text":"Agree without asking any questions or flagging the cost to your own schedule.","trait_deltas":{"TP":1,"PS":-1,"CM":-1}},{"text":"Discuss the trade-off honestly with your lead and the other discipline, then agree to a workable compromise.","trait_deltas":{"TP":2,"CM":2,"PS":1}},{"text":"Agree reluctantly and let your resentment show throughout the interaction.","trait_deltas":{"TP":-1,"CM":-1}}]},{"id":"M-TP-07","topic":"TP","prompt":"You disagree with a decision your team made collectively in a meeting you weren't part of. What do you do?","options":[{"text":"Ignore the decision and do it your way anyway.","trait_deltas":{"TP":-2,"CM":-1}},{"text":"Comply outwardly but complain about it to others behind the scenes.","trait_deltas":{"TP":-1,"CM":-1}},{"text":"Raise your concern constructively with the team or decision-maker, then support the decision once discussed.","trait_deltas":{"TP":2,"CM":2,"LD":1}},{"text":"Go along with it without ever voicing your view, even in the moment.","trait_deltas":{"TP":0,"CM":-1}}]},{"id":"M-CM-01","topic":"CM","prompt":"You need to explain a complex clash issue to non-technical stakeholders (e.g. the client's facilities team) who don't understand BIM jargon. What's your approach?","options":[{"text":"Use full technical terminology since it's the most precise.","trait_deltas":{"CM":-2}},{"text":"Simplify heavily, using analogies and avoiding jargon, checking they understood before moving on.","trait_deltas":{"CM":2,"PS":1}},{"text":"Let a colleague handle the explanation instead.","trait_deltas":{"CM":-1}},{"text":"Give a quick technical summary and move on regardless of whether they followed.","trait_deltas":{"CM":-2}}]},{"id":"M-CM-02","topic":"CM","prompt":"An important coordination decision was made verbally in a meeting. What do you do to make sure nothing gets lost?","options":[{"text":"Assume everyone remembers and skip writing it down.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Write a brief but clear summary and share it with everyone involved right after the meeting.","trait_deltas":{"CM":2,"PS":1}},{"text":"Write detailed notes only for your own records, not shared with others.","trait_deltas":{"CM":-1}},{"text":"Wait for someone else to write meeting minutes.","trait_deltas":{"CM":-1,"LD":-1}}]},{"id":"M-CM-03","topic":"CM","prompt":"A teammate's message about a coordination issue is unclear and could mean two very different things. What do you do?","options":[{"text":"Guess at the intended meaning and proceed.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Ask a clarifying question immediately before proceeding.","trait_deltas":{"CM":2,"PS":1}},{"text":"Proceed with the interpretation that's easiest for you, regardless of likely intent.","trait_deltas":{"CM":-2,"ET":-1}},{"text":"Ignore the message until they follow up.","trait_deltas":{"CM":-1}}]},{"id":"M-CM-04","topic":"CM","prompt":"Partway through a task, you realize the brief you were given was ambiguous and you've made an assumption that might be wrong. What do you do?","options":[{"text":"Keep going and hope your assumption was right.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Reach out early to confirm your assumption before investing more time.","trait_deltas":{"CM":2,"PS":2}},{"text":"Finish the task your way and mention the ambiguity only if someone asks.","trait_deltas":{"CM":-1,"PS":-1}},{"text":"Redo the task multiple ways to cover all interpretations, without asking anyone.","trait_deltas":{"CM":-1,"PS":-1}}]},{"id":"M-CM-05","topic":"CM","prompt":"A client questions why a deliverable took longer than the timesheet estimate implied. What's the best response?","options":[{"text":"Say it was due to 'technical issues' without further detail.","trait_deltas":{"CM":-1}},{"text":"Give a clear, honest breakdown of what the extra time involved and why, framed constructively.","trait_deltas":{"CM":2,"ET":2,"PS":1}},{"text":"Attribute the delay to a teammate.","trait_deltas":{"CM":-2,"ET":-1,"DR":-2}},{"text":"Avoid answering directly and change the subject.","trait_deltas":{"CM":-2,"ET":-1}}]},{"id":"M-CM-06","topic":"CM","prompt":"Your manager's instructions for a task conflict with what the client previously told you directly. What do you do?","options":[{"text":"Follow your manager's instructions without mentioning the conflict.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Follow the client's version without mentioning the conflict to your manager.","trait_deltas":{"CM":-2,"PS":-1}},{"text":"Point out the discrepancy to your manager promptly so it can be clarified before proceeding.","trait_deltas":{"CM":2,"PS":2}},{"text":"Pick whichever seems easier to execute technically.","trait_deltas":{"CM":-2,"PS":-1}}]},{"id":"M-PS-01","topic":"PS","prompt":"Two disciplines' models disagree on a critical dimension by 200mm, discovered the day before an issue-for-construction deadline. What's your first move?","options":[{"text":"Pick whichever number looks right and proceed.","trait_deltas":{"PS":-2,"ET":-1}},{"text":"Escalate immediately with both models/screenshots to your lead, flagging it as blocking until jointly resolved.","trait_deltas":{"PS":2,"CM":2,"LD":1}},{"text":"Issue the set anyway with a note about the discrepancy.","trait_deltas":{"PS":-1,"ET":-1}},{"text":"Wait to see if someone else notices it first.","trait_deltas":{"PS":-2,"LD":-2,"CM":-2}}]},{"id":"M-PS-02","topic":"PS","prompt":"You realize you misjudged the time a modeling task would take and are now behind, with the deadline in two days. What do you do?","options":[{"text":"Say nothing and work faster, skipping some QA checks to catch up.","trait_deltas":{"PS":-1,"ET":-1,"CM":-1}},{"text":"Inform your lead early with a realistic revised estimate, and ask about reprioritizing scope or support.","trait_deltas":{"PS":2,"CM":2,"ET":1,"LD":1}},{"text":"Wait until the deadline to explain what happened.","trait_deltas":{"CM":-2,"ET":-1,"PS":-1}},{"text":"Attribute the slip mainly to an unclear brief at the start.","trait_deltas":{"CM":-1,"ET":-1,"LD":-1}}]},{"id":"M-PS-03","topic":"PS","prompt":"A software malfunction during a critical work session right before a deadline costs you an hour of unsaved work. What do you do?","options":[{"text":"Panic and immediately tell everyone the deadline is impossible.","trait_deltas":{"PS":-2,"CM":-1}},{"text":"Quickly assess what's actually lost, try alternate recovery options, and give a realistic revised estimate to your lead.","trait_deltas":{"PS":2,"CM":1,"LD":1}},{"text":"Try to silently redo the work without adjusting the estimate or informing anyone.","trait_deltas":{"PS":-1,"CM":-1}},{"text":"Blame the software publicly and wait for instructions.","trait_deltas":{"PS":-1,"CM":-1}}]},{"id":"M-PS-04","topic":"PS","prompt":"You're given conflicting information from two sources about a critical requirement (e.g. ceiling height) for the same space. What's your approach?","options":[{"text":"Pick the source that's more convenient for your existing work.","trait_deltas":{"PS":-2,"ET":-1}},{"text":"Cross-check both sources against the master documents/BEP and escalate if still unresolved.","trait_deltas":{"PS":2,"CM":1}},{"text":"Use whichever number was given most recently, regardless of source reliability.","trait_deltas":{"PS":-1}},{"text":"Proceed with an average of the two numbers without verifying either.","trait_deltas":{"PS":-2}}]},{"id":"M-PS-05","topic":"PS","prompt":"A task turns out to be more complex than expected, and you're not sure of the best technical approach. What do you do?","options":[{"text":"Guess and hope it works out.","trait_deltas":{"PS":-2}},{"text":"Research standard approaches, and if still unsure, ask a more experienced colleague before committing significant time.","trait_deltas":{"PS":2,"TP":1,"CM":1}},{"text":"Pick the first approach that comes to mind and stick with it regardless of new information.","trait_deltas":{"PS":-1}},{"text":"Avoid the task and hope someone else picks it up.","trait_deltas":{"PS":-2,"LD":-1}}]},{"id":"M-PS-06","topic":"PS","prompt":"You're assigned a task with insufficient information to complete it accurately, and the person who could clarify is unavailable for a day. The deadline is tomorrow. What do you do?","options":[{"text":"Guess and proceed with your best assumption, telling no one.","trait_deltas":{"PS":-2,"CM":-1}},{"text":"Make a reasonable, clearly-documented assumption, proceed cautiously on lower-risk parts first, and flag the exact open question as soon as the person is available.","trait_deltas":{"PS":2,"CM":2}},{"text":"Stop all work on the task until the person is available.","trait_deltas":{"PS":-1,"LD":-1}},{"text":"Ask a random colleague who also doesn't know the answer and treat their guess as fact.","trait_deltas":{"PS":-1}}]},{"id":"M-LD-01","topic":"LD","prompt":"A newer teammate keeps making the same mistake, creating rework for you. Even though you're not their manager, what do you do?","options":[{"text":"Redo their work yourself each time to avoid confrontation.","trait_deltas":{"LD":-1,"TP":-1}},{"text":"Report it directly to management asking for them to be reprimanded.","trait_deltas":{"LD":0,"CM":-1,"DR":-1}},{"text":"Sit with them, explain the correct method, and check their next few submissions before escalating further.","trait_deltas":{"LD":2,"CM":2,"TP":1}},{"text":"Point out the mistake publicly in the coordination meeting so others are aware.","trait_deltas":{"LD":-1,"CM":-2}}]},{"id":"M-LD-02","topic":"LD","prompt":"During a chaotic coordination crunch, no one has clearly taken charge of triaging what to fix first. What do you do, even without formal authority?","options":[{"text":"Wait for someone senior to take charge.","trait_deltas":{"LD":-2}},{"text":"Step in to suggest a simple triage/priority order for the group to align around, without waiting to be asked.","trait_deltas":{"LD":2,"PS":1,"CM":1}},{"text":"Focus only on your own piece and let the group figure out priorities.","trait_deltas":{"LD":-1}},{"text":"Take over the whole thing yourself without checking with anyone.","trait_deltas":{"LD":-1,"TP":-1}}]},{"id":"M-LD-03","topic":"LD","prompt":"You disagree with a modeling standard your studio uses and believe your own method is better. What do you do?","options":[{"text":"Quietly use your own method since you're confident it's better.","trait_deltas":{"LD":-1,"CM":-1}},{"text":"Raise it with your lead/BIM manager with reasoning and evidence, following the current standard while it's discussed.","trait_deltas":{"LD":2,"CM":2,"PS":1}},{"text":"Complain to colleagues that the standard is outdated.","trait_deltas":{"LD":-1,"CM":-2}},{"text":"Follow the standard without ever raising the concern.","trait_deltas":{"LD":-1}}]},{"id":"M-LD-04","topic":"LD","prompt":"A junior colleague asks you, an experienced modeler, whether they're ready to take on more responsibility. What do you do?","options":[{"text":"Give a quick generic answer and move on.","trait_deltas":{"LD":-1,"CM":-1}},{"text":"Take the time to give specific, honest feedback based on what you've actually observed of their work, and encourage a concrete next step.","trait_deltas":{"LD":2,"CM":2,"TP":1}},{"text":"Tell them to ask their manager instead.","trait_deltas":{"LD":-1}},{"text":"Avoid giving an honest answer to spare their feelings.","trait_deltas":{"LD":-1,"CM":-1,"ET":-1}}]},{"id":"M-DR-01","topic":"DR","prompt":"In a coordination meeting, a structural engineer insists a beam position is fixed and MEP must reroute around it — even though that reroute would violate minimum ceiling clearance required by code. What do you do?","options":[{"text":"Agree immediately to avoid conflict and reroute despite the code issue.","trait_deltas":{"PS":-1,"ET":-1,"DR":-1}},{"text":"Push back forcefully insisting structural must move the beam, without proposing alternatives.","trait_deltas":{"DR":-1,"CM":-1}},{"text":"Clearly flag the code conflict with technical justification and propose 2-3 alternatives for the group to evaluate together.","trait_deltas":{"PS":2,"CM":2,"DR":2,"LD":1}},{"text":"Stay quiet in the meeting but raise the concern privately with your manager afterward.","trait_deltas":{"PS":0,"CM":-1,"DR":-1,"LD":-1}}]},{"id":"M-DR-02","topic":"DR","prompt":"During a late-night coordination call under deadline pressure, a colleague is visibly stressed and starts snapping at others. What do you do?","options":[{"text":"Ignore it — not your problem.","trait_deltas":{"CM":-1,"DR":-1}},{"text":"Snap back to defend the person being criticized.","trait_deltas":{"CM":-1,"DR":-1}},{"text":"Acknowledge the stress calmly, refocus on the specific issue, and suggest a short break if needed.","trait_deltas":{"CM":2,"DR":2,"LD":1}},{"text":"Report the colleague's behavior to management right after the call without addressing it in the moment.","trait_deltas":{"CM":-1,"DR":-1}}]},{"id":"M-DR-03","topic":"DR","prompt":"Two teammates on your project openly disagree about the right modeling approach in front of you and ask you to weigh in. What do you do?","options":[{"text":"Avoid taking a side to stay neutral, even if one is clearly more correct.","trait_deltas":{"DR":-1,"PS":-1}},{"text":"Give your honest technical opinion based on the merits, while being respectful of both people's perspectives.","trait_deltas":{"DR":2,"CM":2,"PS":1}},{"text":"Side with whichever one is more senior, regardless of the merits.","trait_deltas":{"DR":-2}},{"text":"Escalate it immediately without offering your own view first.","trait_deltas":{"DR":-1}}]},{"id":"M-OM-01","topic":"OM","prompt":"A recurring coordination issue keeps causing delays across multiple projects, not just yours. What's the best individual response as a modeler (not yet a manager)?","options":[{"text":"Keep solving it manually every time it comes up on your own projects.","trait_deltas":{"OM":-1,"PS":0}},{"text":"Document the recurring pattern and its impact, and proactively suggest it to your lead as a process issue worth fixing at the source.","trait_deltas":{"OM":2,"PS":2,"CM":1}},{"text":"Assume it's someone else's job to notice and say nothing.","trait_deltas":{"OM":-1,"PS":-1}},{"text":"Complain about it informally without ever raising it formally.","trait_deltas":{"OM":-1,"CM":-1}}]},{"id":"M-OM-02","topic":"OM","prompt":"Your studio is under resourcing pressure across several projects at once, and you finish your own task early. What do you do?","options":[{"text":"Consider your job done and wait for your next assigned task.","trait_deltas":{"OM":-1}},{"text":"Proactively check with your lead whether another project or teammate needs help, given the studio-wide crunch.","trait_deltas":{"OM":2,"TP":1,"LD":1}},{"text":"Use the spare time entirely for personal tasks without telling anyone.","trait_deltas":{"OM":-2}},{"text":"Wait to be told what to do next without asking.","trait_deltas":{"OM":-1}}]},{"id":"M-ET-01","topic":"ET","prompt":"At 6pm you discover an error in the shared central model that will affect three other disciplines' work if not fixed tonight. Fixing it means at least 2 unplanned overtime hours. What do you do?","options":[{"text":"Log off and mention it in tomorrow's meeting since you weren't asked to stay late.","trait_deltas":{"PS":-1,"CM":-1,"LD":-1}},{"text":"Fix it tonight yourself, but don't log the extra hours so it doesn't look like you're padding your timesheet.","trait_deltas":{"PS":1,"CM":-2,"ET":-2},"flag":"ethics_concern"},{"text":"Notify your coordinator immediately about the issue and its downstream impact, offer to fix it tonight, and log the actual time honestly.","trait_deltas":{"PS":2,"CM":2,"ET":2,"LD":1}},{"text":"Fix it tonight but don't mention it unless someone asks.","trait_deltas":{"PS":1,"CM":-1,"ET":-1}}]},{"id":"M-ET-02","topic":"ET","prompt":"Your manager asks you to sign off on a coordination model as 'clash-free,' but you know a few unresolved clashes remain in a low-visibility area. What do you do?","options":[{"text":"Sign off since your manager asked.","trait_deltas":{"ET":-2},"flag":"ethics_concern"},{"text":"Decline to sign off and clearly document the remaining clashes and their risk before any decision is made.","trait_deltas":{"ET":2,"CM":2,"LD":1}},{"text":"Sign off but quietly tell a colleague about the unresolved clashes.","trait_deltas":{"ET":-1,"CM":-1},"flag":"ethics_concern"},{"text":"Delay responding and hope someone else handles it.","trait_deltas":{"ET":-1,"LD":-1}}]}]}]}$modeler_schema$::jsonb
)
on conflict (id) do update set
  title = excluded.title,
  duration_minutes = excluded.duration_minutes,
  schema = excluded.schema,
  updated_at = now();

insert into public.tests (id, title, duration_minutes, schema)
values (
  'leadership',
  'SCORE — Assistant Manager / Manager Assessment',
  30,
  $leadership_schema${"testId":"leadership","program":"BIMstream SCORE","programFullName":"Situational Competency & Organizational Readiness Evaluation","title":"SCORE — Assistant Manager / Manager Assessment","durationMinutes":30,"audience":"Assistant Managers and Managers overseeing BIM coordination teams","description":"Purely HR/behavioral instrument, 30 questions at ~60 seconds each. Technical/software skill is assessed separately (technical test + Personal Interview), so this test carries no technical items at all. Weighted for a managerial role: Leadership gets the most questions, Communication and Team Play next, then Problem-Solving; Dispute Resolution and Organizational Mindset carry smaller dedicated quotas (though still higher than at the modeler level, reflecting real managerial exposure), and Ethics is a minimal but always-active dimension — ethics-concern flags can surface on any question, not just the 2 dedicated ones.","topicWeights":{"LD":7,"CM":6,"TP":5,"PS":5,"DR":3,"OM":2,"ET":2},"sections":[{"type":"situational_judgment","instructions":"Choose the option that best reflects how you would actually act. There is no single 'correct' answer — pick the one truest to your instinct.","questions":[{"id":"L-LD-01","topic":"LD","prompt":"A junior staff member makes a significant error that reaches the client before being caught. As team lead, what's your response?","options":[{"text":"Quietly fix it and never mention it to the client to avoid embarrassment.","trait_deltas":{"ET":-2,"CM":-1},"flag":"ethics_concern"},{"text":"Blame the junior staff member to the client to protect yourself.","trait_deltas":{"CM":-2,"LD":-2,"DR":-1,"ET":-1}},{"text":"Own it with the client, communicate the correction and prevention plan, and address the root cause privately and constructively with the staff member.","trait_deltas":{"LD":2,"CM":2,"ET":2}},{"text":"Terminate the junior staff member immediately.","trait_deltas":{"LD":-2,"ET":-1}}]},{"id":"L-LD-02","topic":"LD","prompt":"A major clash is discovered right before a permit submission and your team is panicking. What's your leadership approach?","options":[{"text":"Take over every task yourself to make sure it's done right.","trait_deltas":{"LD":-1}},{"text":"Stay calm, quickly triage the issue, delegate clear ownership of specific parts, and set a tight but realistic timeline with check-ins.","trait_deltas":{"LD":2,"PS":2,"CM":2}},{"text":"Let the team figure it out without your involvement, to avoid micromanaging.","trait_deltas":{"LD":-2,"PS":-1}},{"text":"Focus on identifying who's at fault before solving the technical problem.","trait_deltas":{"LD":-2,"DR":-2,"CM":-1}}]},{"id":"L-LD-03","topic":"LD","prompt":"A talented team member consistently disrespects deadlines but produces excellent technical work. How do you manage this?","options":[{"text":"Overlook the deadline issue entirely because the work quality is high.","trait_deltas":{"LD":-1,"PS":-1}},{"text":"Address the pattern directly and specifically, set clear expectations and consequences, while acknowledging their strength.","trait_deltas":{"LD":2,"CM":2,"PS":1}},{"text":"Criticize them publicly in front of the team.","trait_deltas":{"CM":-2,"LD":-1,"DR":-1}},{"text":"Quietly reassign their tasks to others without discussing it with them.","trait_deltas":{"CM":-2,"LD":-1}}]},{"id":"L-LD-04","topic":"LD","prompt":"A new Assistant Manager under you is eager but making decisions above their authority level, causing confusion on the team. How do you handle it?","options":[{"text":"Publicly undermine their decisions in front of the team.","trait_deltas":{"LD":-2,"CM":-1,"DR":-1}},{"text":"Have a direct, supportive conversation clarifying decision boundaries, mentor them on judgment, and reinforce it consistently.","trait_deltas":{"LD":2,"CM":2,"PS":1}},{"text":"Say nothing and quietly override their decisions when you notice them.","trait_deltas":{"LD":-1,"CM":-2}},{"text":"Remove their decision-making authority entirely without explanation.","trait_deltas":{"LD":-1,"CM":-1}}]},{"id":"L-LD-05","topic":"LD","prompt":"Productivity data (billed hours vs. deliverables) shows one team member underperforming for several months. What's your approach as manager?","options":[{"text":"Reduce that person's billed hours retroactively without discussing it with them or the client.","trait_deltas":{"ET":-2,"CM":-1},"flag":"ethics_concern"},{"text":"Have a private, evidence-based performance conversation, identify root causes, set a clear improvement plan with support, and follow up.","trait_deltas":{"LD":2,"CM":2,"PS":1}},{"text":"Let it continue to avoid a difficult conversation.","trait_deltas":{"LD":-2,"PS":-1}},{"text":"Reassign all their work to others without ever discussing performance with them directly.","trait_deltas":{"LD":-1,"CM":-1}}]},{"id":"L-LD-06","topic":"LD","prompt":"You're promoted to manage former peers. One of them resents reporting to you now. What do you do?","options":[{"text":"Avoid giving them any direction to keep the peace.","trait_deltas":{"LD":-2}},{"text":"Have an honest, direct conversation acknowledging the shift, clarify expectations, and earn credibility through fair, consistent leadership.","trait_deltas":{"LD":2,"CM":2,"TP":1}},{"text":"Assert your authority forcefully to establish dominance early.","trait_deltas":{"LD":-1,"CM":-1,"DR":-1}},{"text":"Report their attitude to your own manager immediately without addressing it yourself.","trait_deltas":{"LD":-1}}]},{"id":"L-LD-07","topic":"LD","prompt":"A high-priority client project needs a lead assigned from your team, and two capable people want the role. How do you decide?","options":[{"text":"Pick whoever asks most persistently.","trait_deltas":{"LD":-1}},{"text":"Assess based on project fit, availability, and development opportunity, communicate the reasoning transparently to both, and offer the other a clear next opportunity.","trait_deltas":{"LD":2,"CM":2,"ET":1}},{"text":"Avoid deciding and let them sort it out between themselves.","trait_deltas":{"LD":-1}},{"text":"Choose based on personal preference without explaining the reasoning.","trait_deltas":{"LD":-1,"CM":-1}}]},{"id":"L-CM-01","topic":"CM","prompt":"A client is unhappy about slipped deadlines and threatens to escalate to your director. What's your approach?","options":[{"text":"Avoid the client's calls until you have better news.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Proactively reach out, acknowledge the issue honestly, present a clear recovery plan with realistic dates, and update them regularly.","trait_deltas":{"CM":2,"LD":2,"ET":1}},{"text":"Attribute the delay entirely to subcontractors/other disciplines when speaking with the client.","trait_deltas":{"CM":-1,"ET":-1,"DR":-1}},{"text":"Promise an unrealistic recovery date just to calm the client down.","trait_deltas":{"ET":-1,"CM":-1,"PS":-1}}]},{"id":"L-CM-02","topic":"CM","prompt":"A client asks directly whether your team can meet an aggressive deadline you privately doubt is realistic. What do you say?","options":[{"text":"Say yes to avoid disappointing them, and figure it out later.","trait_deltas":{"ET":-1,"CM":-1,"PS":-1}},{"text":"Give an honest assessment of the risks and what would need to be true to hit the date, then propose options.","trait_deltas":{"CM":2,"ET":2,"PS":2,"LD":1}},{"text":"Say no immediately without offering alternatives.","trait_deltas":{"CM":-1,"PS":-1}},{"text":"Avoid giving a direct answer.","trait_deltas":{"CM":-2}}]},{"id":"L-CM-03","topic":"CM","prompt":"A client says your own communication style in status meetings is 'too technical and hard to follow.' How do you respond?","options":[{"text":"Dismiss it — technical accuracy matters more than simplicity.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Take the feedback seriously, adapt your approach for that audience, and check in for ongoing feedback.","trait_deltas":{"CM":2,"LD":1,"PS":1}},{"text":"Get defensive and explain why the client should follow your explanations more closely.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Delegate all future client meetings to someone else without addressing the issue yourself.","trait_deltas":{"CM":-1,"LD":-1}}]},{"id":"L-CM-04","topic":"CM","prompt":"Budget cuts mean reducing your team's software license count, which will slow some work. How do you communicate this internally?","options":[{"text":"Don't explain the reasoning — just enforce the cut.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Explain the business context honestly, involve the team in prioritizing affected workflows, and set realistic expectations with stakeholders.","trait_deltas":{"CM":2,"LD":2,"PS":1}},{"text":"Blame 'management' vaguely without owning the decision as a leader.","trait_deltas":{"CM":-1,"LD":-1}},{"text":"Delay telling the team until problems arise from the change.","trait_deltas":{"CM":-2,"LD":-1}}]},{"id":"L-CM-05","topic":"CM","prompt":"You need to deliver difficult news to the whole team — a valued project was cancelled or scope significantly reduced. How do you approach it?","options":[{"text":"Send a brief email and avoid further discussion.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Hold a live conversation, explain context honestly, acknowledge the impact, and answer questions directly.","trait_deltas":{"CM":2,"LD":2}},{"text":"Let it leak out informally rather than addressing it directly.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Downplay the significance to avoid concern, even if that means being misleading.","trait_deltas":{"CM":-1,"ET":-1}}]},{"id":"L-CM-06","topic":"CM","prompt":"Two people on your team interpret your instructions for a task completely differently, causing duplicated/conflicting effort. What do you do?","options":[{"text":"Blame them for not asking enough questions.","trait_deltas":{"CM":-2,"LD":-1}},{"text":"Take ownership of the miscommunication, clarify immediately, and adjust your future instructions to be more explicit.","trait_deltas":{"CM":2,"LD":1,"PS":1}},{"text":"Let them sort out the confusion themselves.","trait_deltas":{"CM":-1,"LD":-1}},{"text":"Pick whichever interpretation is more convenient and move forward without explaining.","trait_deltas":{"CM":-2}}]},{"id":"L-TP-01","topic":"TP","prompt":"Two previously siloed discipline sub-teams under you rarely collaborate and duplicate effort. How do you build a stronger sense of shared team identity?","options":[{"text":"Leave it as is since each sub-team still delivers its own work.","trait_deltas":{"TP":-2}},{"text":"Create shared touchpoints (joint reviews, shared goals/recognition) and actively model cross-team collaboration yourself.","trait_deltas":{"TP":2,"LD":2,"CM":1}},{"text":"Merge them formally without addressing the underlying culture issue.","trait_deltas":{"TP":-1}},{"text":"Address it only if a client complains about the disconnect.","trait_deltas":{"TP":-1,"LD":-1}}]},{"id":"L-TP-02","topic":"TP","prompt":"A star performer on your team refuses to mentor or share knowledge with others, protecting their own indispensability. What do you do?","options":[{"text":"Leave them alone since their individual output is excellent.","trait_deltas":{"TP":-1,"LD":-1}},{"text":"Have a direct conversation linking knowledge-sharing to how you evaluate senior-level contribution, and create structured opportunities for them to mentor.","trait_deltas":{"TP":2,"LD":2,"CM":1}},{"text":"Publicly criticize them for not being a team player.","trait_deltas":{"TP":-1,"CM":-2}},{"text":"Quietly route more mentoring responsibility to others without addressing the root behavior.","trait_deltas":{"TP":-1,"LD":-1}}]},{"id":"L-TP-03","topic":"TP","prompt":"Your team must absorb extra scope with no extra time, and morale is already stretched. How do you rally them?","options":[{"text":"Just assign the extra work and expect people to manage.","trait_deltas":{"TP":-2,"LD":-1}},{"text":"Be transparent about the situation, involve the team in deciding how to divide the load fairly, and acknowledge the extra effort.","trait_deltas":{"TP":2,"LD":2,"CM":2}},{"text":"Take on all the extra work yourself without asking the team.","trait_deltas":{"TP":-1,"LD":-1}},{"text":"Promise rewards you're not sure you can deliver to motivate them.","trait_deltas":{"TP":-1,"ET":-1}}]},{"id":"L-TP-04","topic":"TP","prompt":"A remote or satellite-office team member feels excluded from key decisions made in the main office. What do you do?","options":[{"text":"Assume it's a minor issue since they still receive the final decisions.","trait_deltas":{"TP":-2}},{"text":"Actively include them in relevant discussions going forward and check in on how included they feel.","trait_deltas":{"TP":2,"CM":2,"LD":1}},{"text":"Suggest they raise it themselves if it's really bothering them.","trait_deltas":{"TP":-1,"CM":-1}},{"text":"Address it only if it starts affecting their output.","trait_deltas":{"TP":-1}}]},{"id":"L-TP-05","topic":"TP","prompt":"A Junior and a Senior on the same task are competitive with each other rather than collaborative, and it's affecting quality. What do you do?","options":[{"text":"Let them work it out since some competition can be healthy.","trait_deltas":{"TP":-1,"LD":-1}},{"text":"Set clear shared goals and structure the task so their success is interdependent, addressing the competitive dynamic directly.","trait_deltas":{"TP":2,"LD":2,"DR":1}},{"text":"Separate them onto different tasks without addressing the dynamic.","trait_deltas":{"TP":0,"LD":-1}},{"text":"Reprimand both without understanding the underlying dynamic.","trait_deltas":{"TP":-1,"CM":-1}}]},{"id":"L-PS-01","topic":"PS","prompt":"A team lead under you wants to skip a QA review step to hit a deadline, 'just this once.' What's your call?","options":[{"text":"Approve skipping QA — deadlines matter and it's a one-time thing.","trait_deltas":{"ET":-1,"PS":-1}},{"text":"Say no, but work with the team to find a faster path to complete QA properly rather than skipping it.","trait_deltas":{"ET":2,"PS":2,"LD":1}},{"text":"Approve it without discussion since you trust the lead's judgment.","trait_deltas":{"ET":-1,"PS":-1}},{"text":"Say no without offering any alternative path to still meet the deadline.","trait_deltas":{"LD":-1,"PS":-1}}]},{"id":"L-PS-02","topic":"PS","prompt":"A client's facilities team insists on a design change that conflicts with a code-compliance issue your BIM team identified. What do you do?","options":[{"text":"Implement the client's requested change since they're paying for the project.","trait_deltas":{"ET":-2,"PS":-1},"flag":"ethics_concern"},{"text":"Clearly and formally communicate the code conflict and risk, get the decision documented, and escalate internally and to the client's leadership before implementing anything non-compliant.","trait_deltas":{"ET":2,"PS":2,"CM":2,"LD":1}},{"text":"Implement the change but have a junior document it quietly as a CYA measure, without informing the client formally.","trait_deltas":{"ET":-1,"CM":-1}},{"text":"Refuse to discuss it further with the client.","trait_deltas":{"CM":-2,"DR":-1}}]},{"id":"L-PS-03","topic":"PS","prompt":"Your team can hit the deadline OR maintain full quality, but not both, and the client hasn't been made aware of this trade-off. What's your approach as manager?","options":[{"text":"Quietly cut quality to hit the deadline without telling the client.","trait_deltas":{"PS":-2,"ET":-1,"CM":-1},"flag":"ethics_concern"},{"text":"Present the trade-off honestly to the client and let them decide which matters more, or negotiate additional time/resource.","trait_deltas":{"PS":2,"CM":2,"ET":1}},{"text":"Miss the deadline without any communication in advance.","trait_deltas":{"PS":-2,"CM":-2}},{"text":"Push the team to work unsustainable hours to try to hit both, without addressing the systemic issue.","trait_deltas":{"PS":-1,"LD":-1}}]},{"id":"L-PS-04","topic":"PS","prompt":"Two competing internal priorities — a strategic new client and an existing client's ongoing work — both need your best people at the same time. How do you resolve the resourcing conflict?","options":[{"text":"Give the new client whatever they want since they're strategically important.","trait_deltas":{"PS":-1,"OM":-1}},{"text":"Evaluate objectively against business priorities, communicate trade-offs transparently to both stakeholders, and look for creative resourcing options before choosing.","trait_deltas":{"PS":2,"OM":1,"CM":1}},{"text":"Default to whichever client complains loudest.","trait_deltas":{"PS":-2}},{"text":"Split your best people evenly regardless of actual project needs.","trait_deltas":{"PS":-1}}]},{"id":"L-PS-05","topic":"PS","prompt":"A long-standing process at your studio clearly isn't working anymore as the studio has grown, but changing it will be disruptive short-term. What do you do?","options":[{"text":"Leave it alone since change is disruptive and risky.","trait_deltas":{"PS":-1,"OM":-1}},{"text":"Propose and pilot a change with a clear plan to manage the short-term disruption, gathering team input first.","trait_deltas":{"PS":2,"OM":2,"LD":1}},{"text":"Force the change immediately without piloting or consulting anyone.","trait_deltas":{"PS":-1,"TP":-1}},{"text":"Complain about the process being outdated without proposing anything concrete.","trait_deltas":{"PS":-1}}]},{"id":"L-DR-01","topic":"DR","prompt":"Two department leads under you have an ongoing personal conflict that's starting to affect team morale and coordination quality. What do you do?","options":[{"text":"Avoid getting involved since it's a personal matter.","trait_deltas":{"LD":-2,"DR":-2}},{"text":"Meet with each separately, then together, understand root causes, establish clear working agreements, and follow up over time.","trait_deltas":{"LD":2,"DR":2,"CM":2}},{"text":"Publicly reprimand both in a team meeting.","trait_deltas":{"DR":-1,"CM":-1,"LD":-1}},{"text":"Transfer one of them immediately without addressing the root issue.","trait_deltas":{"LD":-1,"DR":-1}}]},{"id":"L-DR-02","topic":"DR","prompt":"A dispute escalates between your team and another team (led by a peer manager) over who's responsible for a coordination failure that affected the client. What do you do?","options":[{"text":"Publicly blame the other team to protect your own team's reputation.","trait_deltas":{"DR":-2,"CM":-1}},{"text":"Meet privately with the peer manager first to understand both sides, focus on resolving the root cause and preventing recurrence rather than assigning blame, then align on a joint message.","trait_deltas":{"DR":2,"CM":2,"LD":1}},{"text":"Avoid engaging with the other manager and let the client draw their own conclusions.","trait_deltas":{"DR":-2}},{"text":"Escalate immediately to senior leadership without attempting to resolve it peer-to-peer first.","trait_deltas":{"DR":-1,"LD":-1}}]},{"id":"L-DR-03","topic":"DR","prompt":"Two of your direct reports have a disagreement about technical approach that's becoming personal rather than professional. What do you do?","options":[{"text":"Let them work it out, since you don't want to seem like you're taking sides.","trait_deltas":{"DR":-2,"LD":-1}},{"text":"Intervene early, separate the technical disagreement from the personal friction, mediate a resolution on the technical point, and address the interpersonal tension directly.","trait_deltas":{"DR":2,"LD":2,"CM":1}},{"text":"Side with whichever one is more senior to end the disagreement quickly.","trait_deltas":{"DR":-2}},{"text":"Reassign one of them to a different task to avoid dealing with the conflict.","trait_deltas":{"DR":-1,"LD":-1}}]},{"id":"L-OM-01","topic":"OM","prompt":"You notice a pattern where multiple projects at your studio hit avoidable delays for the same root-cause reason. What's your response as manager?","options":[{"text":"Handle each project's delay individually as it comes up without addressing the pattern.","trait_deltas":{"OM":-2,"PS":-1}},{"text":"Raise the systemic pattern with studio leadership, propose a root-cause fix, and track whether it actually improves outcomes across projects.","trait_deltas":{"OM":2,"LD":1,"PS":1}},{"text":"Assume other managers will notice and raise it themselves.","trait_deltas":{"OM":-2}},{"text":"Mention it informally in passing without pursuing a real fix.","trait_deltas":{"OM":-1}}]},{"id":"L-OM-02","topic":"OM","prompt":"A decision that's good for your team's short-term numbers would be mildly harmful to the studio's reputation with a client relationship that matters long-term. What do you do?","options":[{"text":"Prioritize your team's short-term numbers since that's what you're measured on.","trait_deltas":{"OM":-2,"ET":-1}},{"text":"Weigh the long-term studio/client relationship appropriately, even if it means a less favorable short-term outcome for your own team's metrics, and explain the reasoning upward.","trait_deltas":{"OM":2,"LD":1,"ET":1}},{"text":"Make the short-term-favorable choice without considering or mentioning the long-term angle.","trait_deltas":{"OM":-2}},{"text":"Avoid making the decision and hope it resolves itself.","trait_deltas":{"OM":-1,"LD":-1}}]},{"id":"L-ET-01","topic":"ET","prompt":"Senior management asks you to reduce hours reported to a client without reducing the actual work required, to preserve a fee cap. What do you do?","options":[{"text":"Comply, since it's a direction from senior management.","trait_deltas":{"ET":-2,"LD":-1},"flag":"ethics_concern"},{"text":"Push back clearly, explain the ethical/legal risk of misreporting billed hours, and propose alternatives (scope renegotiation, efficiency review).","trait_deltas":{"ET":2,"LD":2,"CM":1}},{"text":"Comply, but keep a private record for yourself in case of future questions.","trait_deltas":{"ET":-1,"LD":-1},"flag":"ethics_concern"},{"text":"Ignore the instruction without addressing it directly with management.","trait_deltas":{"CM":-1,"LD":-1}}]},{"id":"L-ET-02","topic":"ET","prompt":"You discover a deliverable sent to a client last week contained a significant, uncaught modeling error affecting cost estimates. What do you do?","options":[{"text":"Wait to see if the client notices before saying anything.","trait_deltas":{"ET":-2,"CM":-1},"flag":"ethics_concern"},{"text":"Proactively notify the client as soon as possible, explain the correction, and review internal QA to prevent recurrence.","trait_deltas":{"ET":2,"CM":2,"LD":2,"PS":1}},{"text":"Correct it quietly in the next deliverable without flagging the earlier error.","trait_deltas":{"ET":-2,"CM":-1},"flag":"ethics_concern"},{"text":"Attribute the error to the software or an external vendor when informing the client.","trait_deltas":{"ET":-1,"CM":-1}}]}]}]}$leadership_schema$::jsonb
)
on conflict (id) do update set
  title = excluded.title,
  duration_minutes = excluded.duration_minutes,
  schema = excluded.schema,
  updated_at = now();
